public class AVLChecker {

    static class Node {
        int val; Node left, right;
        Node(int v) { val = v; }
    }

    private int height(Node node) {
        if (node == null) return -1;
        return 1 + Math.max(height(node.left), height(node.right));
    }

    public int balanceFactor(Node node) {
        if (node == null) return 0;
        return height(node.left) - height(node.right);
    }

    public boolean isAVL(Node root) {
        // TODO: true if |balanceFactor| <= 1 at EVERY node (including subtrees)
        return false;
    }

    public void printBalanceFactors(Node root) {
        if (root == null) return;
        printBalanceFactors(root.left);
        System.out.println("Node " + root.val + ": BF=" + balanceFactor(root));
        printBalanceFactors(root.right);
    }

    public static void main(String[] args) {
        AVLChecker avl = new AVLChecker();
        // Balanced AVL tree
        Node balanced = new Node(10);
        balanced.left = new Node(5); balanced.right = new Node(15);
        balanced.left.left = new Node(3); balanced.left.right = new Node(7);
        System.out.println("Balanced AVL: " + avl.isAVL(balanced));
        avl.printBalanceFactors(balanced);
        // Unbalanced tree
        Node unbalanced = new Node(10);
        unbalanced.left = new Node(5);
        unbalanced.left.left = new Node(3);
        unbalanced.left.left.left = new Node(1);
        System.out.println("Unbalanced: " + avl.isAVL(unbalanced));
    }
}

public class AVLRotations {

    static class Node {
        int val, height;
        Node left, right;
        Node(int v) { val = v; height = 1; }
    }

    private int height(Node n) { return n == null ? 0 : n.height; }
    private void updateHeight(Node n) {
        if (n != null) n.height = 1 + Math.max(height(n.left), height(n.right));
    }

    public Node rotateRight(Node y) {
        // y's left child (x) becomes new root; y becomes x's right child
        Node x = y.left;
        Node T2 = x.right;
        x.right = y;
        y.left = T2;
        updateHeight(y);
        updateHeight(x);
        return x; // new root
    }

    public Node rotateLeft(Node x) {
        // TODO: symmetric to rotateRight
        return x;
    }

    public Node rotateLR(Node z) {
        // Left-Right case: rotate left on z.left, then rotate right on z
        z.left = rotateLeft(z.left);
        return rotateRight(z);
    }

    public Node rotateRL(Node z) {
        // TODO: Right-Left case: rotate right on z.right, then rotate left on z
        return z;
    }

    private void printTree(Node root, String prefix) {
        if (root == null) return;
        System.out.println(prefix + root.val + "(h=" + root.height + ")");
        printTree(root.left, prefix + "L:");
        printTree(root.right, prefix + "R:");
    }

    public static void main(String[] args) {
        AVLRotations ar = new AVLRotations();
        // Right rotation: 30->20->10 (left-heavy)
        Node z = new Node(30);
        z.left = new Node(20); z.left.left = new Node(10);
        ar.updateHeight(z.left.left); ar.updateHeight(z.left); ar.updateHeight(z);
        System.out.println("Before right rotation:");
        ar.printTree(z, "");
        z = ar.rotateRight(z);
        System.out.println("After right rotation:");
        ar.printTree(z, "");
    }
}

public class SimpleAVL {

    static class Node {
        int val, height;
        Node left, right;
        Node(int v) { val = v; height = 1; }
    }

    private int height(Node n) { return n == null ? 0 : n.height; }
    private int bf(Node n) { return n == null ? 0 : height(n.left) - height(n.right); }
    private void updateHeight(Node n) { if(n!=null) n.height=1+Math.max(height(n.left),height(n.right)); }

    private Node rotateRight(Node y) {
        Node x=y.left,T2=x.right; x.right=y; y.left=T2; updateHeight(y); updateHeight(x); return x;
    }
    private Node rotateLeft(Node x) {
        Node y=x.right,T2=y.left; y.left=x; x.right=T2; updateHeight(x); updateHeight(y); return y;
    }

    public Node insert(Node node, int val) {
        if (node == null) return new Node(val);
        if (val < node.val) node.left = insert(node.left, val);
        else if (val > node.val) node.right = insert(node.right, val);
        else return node;
        updateHeight(node);
        int balance = bf(node);
        // TODO: apply rotations for 4 imbalance cases
        // LL: balance>1 && val < node.left.val -> rotateRight
        // RR: balance<-1 && val > node.right.val -> rotateLeft
        // LR: balance>1 && val > node.left.val -> rotateLeft(node.left), rotateRight
        // RL: balance<-1 && val < node.right.val -> rotateRight(node.right), rotateLeft
        return node;
    }

    private void inorder(Node root) {
        if (root == null) return;
        inorder(root.left); System.out.print(root.val + " "); inorder(root.right);
    }

    public static void main(String[] args) {
        SimpleAVL avl = new SimpleAVL();
        Node root = null;
        for (int v : new int[]{30, 20, 10, 25, 40}) root = avl.insert(root, v);
        System.out.print("Inorder (must be sorted): ");
        avl.inorder(root);
        System.out.println();
        System.out.println("Root (balanced): " + root.val);
    }
}
